+type jwksCache struct {
+	mu        sync.Mutex
+	keys      map[string]*rsa.PublicKey
+	fetchedAt time.Time
+	ttl       time.Duration
+}
+
+func newJWKSCache(ttl time.Duration) *jwksCache {
+	if ttl <= 0 {
+		ttl = defaultJWKSCacheTTL
+	}
+	return &jwksCache{
+		keys: make(map[string]*rsa.PublicKey),
+		ttl:  ttl,
+	}
+}
+
+func (c *jwksCache) getKey(ctx context.Context, jwksURL, kid string) (*rsa.PublicKey, error) {
+	c.mu.Lock()
+	if time.Since(c.fetchedAt) < c.ttl && len(c.keys) > 0 {
+		if kid == "" && len(c.keys) == 1 {
+			for _, key := range c.keys {
+				c.mu.Unlock()
+				return key, nil
+			}
+		}
+		if key, ok := c.keys[kid]; ok {
+			c.mu.Unlock()
+			return key, nil
+		}
+	}
+	c.mu.Unlock()
+
+	keys, err := fetchJWKSKeys(ctx, jwksURL)
+	if err != nil {
+		return nil, err
+	}
+
+	c.mu.Lock()
+	c.keys = keys
+	c.fetchedAt = time.Now()
+	c.mu.Unlock()
+
+	if kid == "" && len(keys) == 1 {
+		for _, key := range keys {
+			return key, nil
+		}
+	}
+	key, ok := keys[kid]
+	if !ok {
+		return nil, fmt.Errorf("jwt kid not found in jwks")
+	}
+	return key, nil
+}
+
+type jwksPayload struct {
+	Keys []jwk `json:"keys"`
+}
+
+type jwk struct {
+	Kty string `json:"kty"`
+	Kid string `json:"kid"`
+	Alg string `json:"alg"`
+	Use string `json:"use"`
+	N   string `json:"n"`
+	E   string `json:"e"`
+}
+
+func fetchJWKSKeys(ctx context.Context, jwksURL string) (map[string]*rsa.PublicKey, error) {
+	if jwksURL == "" {
+		return nil, fmt.Errorf("jwks url missing")
+	}
+	req, err := http.NewRequestWithContext(ctx, http.MethodGet, jwksURL, nil)
+	if err != nil {
+		return nil, fmt.Errorf("build jwks request: %w", err)
+	}
+	client := &http.Client{Timeout: 5 * time.Second}
+	resp, err := client.Do(req)
+	if err != nil {
+		return nil, fmt.Errorf("fetch jwks: %w", err)
+	}
+	defer resp.Body.Close()
+	if resp.StatusCode != http.StatusOK {
+		body, _ := io.ReadAll(resp.Body)
+		return nil, fmt.Errorf("fetch jwks: status %d: %s", resp.StatusCode, strings.TrimSpace(string(body)))
+	}
+	body, err := io.ReadAll(resp.Body)
+	if err != nil {
+		return nil, fmt.Errorf("read jwks: %w", err)
+	}
+	var payload jwksPayload
+	if err := json.Unmarshal(body, &payload); err != nil {
+		return nil, fmt.Errorf("parse jwks: %w", err)
+	}
+	keys := make(map[string]*rsa.PublicKey)
+	for _, key := range payload.Keys {
+		if key.Kty != "RSA" || key.N == "" || key.E == "" {
+			continue
+		}
+		pub, err := parseRSAPublicKey(key.N, key.E)
+		if err != nil {
+			continue
+		}
+		kid := key.Kid
+		if kid == "" {
+			kid = "default"
+		}
+		keys[kid] = pub
+	}
+	if len(keys) == 0 {
+		return nil, fmt.Errorf("no valid RSA keys in jwks")
+	}
+	return keys, nil
+}
+
+func parseRSAPublicKey(nStr, eStr string) (*rsa.PublicKey, error) {
+	nBytes, err := base64.RawURLEncoding.DecodeString(nStr)
+	if err != nil {
+		return nil, fmt.Errorf("decode jwk n: %w", err)
+	}
+	eBytes, err := base64.RawURLEncoding.DecodeString(eStr)
+	if err != nil {
+		return nil, fmt.Errorf("decode jwk e: %w", err)
+	}
+	n := new(big.Int).SetBytes(nBytes)
+	e := new(big.Int).SetBytes(eBytes)
+	if e.Sign() <= 0 {
+		return nil, fmt.Errorf("invalid jwk exponent")
+	}
+	return &rsa.PublicKey{
+		N: n,
+		E: int(e.Int64()),
+	}, nil
+}

